// Auth + walidacja + normalizacja + budowa TITLE/COMMENTS (BEZ EMOJI!)
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};

if (!$env.INQUIRY_SHARED_TOKEN || headers['x-inquiry-token'] !== $env.INQUIRY_SHARED_TOKEN) {
  return [{ json: { _error: 'auth', _status: 403 } }];
}
const org = body.organizer || {};
if (!org.email || !org.company || (!Array.isArray(body.artists) || !body.artists.length) && (!Array.isArray(body.customArtists) || !body.customArtists.length)) {
  return [{ json: { _error: 'validation', _status: 400 } }];
}

// defensywny strip emoji (Bitrix po cichu gubi pola z emoji)
const strip = (s) => String(s ?? '').replace(/[\u{10000}-\u{10FFFF}]/gu, '').replace(/[\u2600-\u27BF\u2B00-\u2BFF\uFE0F\u200D]/g, '').trim();

const contactName = strip(org.name);
const nameParts = contactName.split(/\s+/).filter(Boolean);
const firstName = nameParts[0] || strip(org.company);
const lastName = nameParts.slice(1).join(' ');
const leadId = /^\d{1,10}$/.test(String(body.leadId ?? '')) ? String(body.leadId) : '';
const city = strip(body.event?.city) || 'miejscowosc nieznana';
let dateDDMM = '';
const dISO = String(body.event?.date || '');
if (/^\d{4}-\d{2}-\d{2}$/.test(dISO)) { const [y, m, d] = dISO.split('-'); dateDDMM = `${d}.${m}.${y}`; }
const styles = (body.styles || []).map(strip).filter(Boolean);
const stylesStr = styles.join(', ') || 'rozne style';
const programs = (body.programs || []).map(strip).filter(Boolean);
const occasion = strip(body.occasion);
const artists = (body.artists || []).map((a) => ({ name: strip(a.name), price: strip(a.priceLabel), busy: !!a.busy }));
const custom = (body.customArtists || []).map(strip).filter(Boolean);

// TITLE zgodny z regexem generatora ofert: Organizator: {miasto} {DD.MM.YYYY} — {gatunek} ({nazwa})
const title = `Organizator: ${city}${dateDDMM ? ' ' + dateDDMM : ''} — ${stylesStr} (${strip(org.company)})`;

const now = new Date();
const lines = [
  'ZAPYTANIE Z APLIKACJI GENERATOR ZAPYTAN',
  `Data zgloszenia: ${now.toLocaleString('pl-PL', { timeZone: 'Europe/Warsaw' })}`,
  '',
  'ORGANIZATOR',
  ...(contactName ? [`Osoba kontaktowa: ${contactName}`] : []),
  `Firma/instytucja: ${strip(org.company)}`,
  `Telefon: ${strip(org.phone)}`,
  `E-mail: ${strip(org.email)}`,
  '',
  'WYDARZENIE',
  `Typ: ${(body.eventTypes || []).map(strip).join(', ') || 'nie podano'}`,
  ...(occasion ? [`Okazja: ${occasion}`] : []),
  ...(programs.length ? [`Program: ${programs.join(', ')}`] : []),
  `Data: ${dateDDMM || 'nie podano'}`,
  `Miejscowość: ${city}${strip(body.event?.postalCode) ? ', ' + strip(body.event?.postalCode) : ''}`,
  `Województwo: ${strip(body.event?.voivodeship) || 'nie podano'}`,
  `Miejsce: ${strip(body.event?.venueType) || 'nie podano'}`,
  `Budżet: ${strip(body.budget) || 'nie podano'}`,
  '',
  'WYBRANI ARTYSCI (zapytanie o dostepnosc)',
  ...(artists.length ? artists.map((a, i) => `${i + 1}. ${a.name}${a.price ? ' (orientacyjnie ' + a.price + ')' : ''}${a.busy ? ' — UWAGA: ZAJETY TERMIN, nie wysylac zapytania' : ''}`) : ['brak']),
];
if (custom.length) {
  lines.push('', 'ARTYSCI SPOZA BAZY (do weryfikacji)');
  custom.forEach((n, i) => lines.push(`${i + 1}. ${n}`));
}
lines.push('', `STYLE: ${stylesStr}`);
if (strip(body.message)) lines.push('', 'WIADOMOSC:', strip(body.message));

return [{ json: {
  title,
  comments: lines.join('\n'),
  company: strip(org.company), phone: strip(org.phone), email: strip(org.email).toLowerCase(),
  contactName, firstName, lastName, leadId,
  eventTypes: (body.eventTypes || []).map(strip), budget: strip(body.budget),
  styles, stylesStr,
  programs, programsStr: programs.join(', '), occasion,
  artistNames: artists.map((a) => a.name), customArtists: custom,
  eventDate: dISO, dateDDMM, city,
  postalCode: strip(body.event?.postalCode), voivodeship: strip(body.event?.voivodeship),
  venueType: strip(body.event?.venueType),
  message: strip(body.message),
} }];

