const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
if (!$env.INQUIRY_SHARED_TOKEN || headers['x-inquiry-token'] !== $env.INQUIRY_SHARED_TOKEN) {
  return [{ json: { _error: 'auth' } }];
}
const strip = (s) => String(s ?? '').replace(/[\u{10000}-\u{10FFFF}]/gu, '').replace(/[\u2600-\u27BF\u2B00-\u2BFF\uFE0F\u200D]/g, '').trim();
const o = body.organizer || {};
const name = strip(o.name), company = strip(o.company), email = strip(o.email).toLowerCase(), phone = strip(o.phone);
if (!name || !email) return [{ json: { _error: 'validation' } }];
const parts = name.split(/\s+/).filter(Boolean);
