// Wzbogacenie CRM (best-effort): bezimienny kontakt dostaje dane organizatora,
// firma jest znajdowana po nazwie albo tworzona i podpinana do kontaktu + deala.
const base = $env.BITRIX24_REST_URL_ANATOL;
const w = $('Walidacja i normalizacja').first().json;
const contactId = $json.contactId;
const req = (m, body) => this.helpers.httpRequest({ method: 'POST', url: base + '/' + m + '.json', body, json: true });
let companyId = 0;
try {
  const c = await req('crm.contact.get', { id: contactId });
  const cf = c.result || {};
  const upd = {};
  if (!cf.NAME && !cf.LAST_NAME && w.firstName) { upd.NAME = w.firstName; if (w.lastName) upd.LAST_NAME = w.lastName; }
  if (!cf.COMPANY_TITLE && !cf.COMPANY_ID && w.company) upd.COMPANY_TITLE = w.company;
  if (Object.keys(upd).length) await req('crm.contact.update', { id: contactId, fields: upd });
  if (w.company) {
    const found = await req('crm.company.list', { filter: { '=TITLE': w.company }, select: ['ID'] });
    if (found.result && found.result.length) companyId = Number(found.result[0].ID);
    else {
      const created = await req('crm.company.add', { fields: {
        TITLE: w.company, ASSIGNED_BY_ID: 19,
        PHONE: w.phone ? [{ VALUE: w.phone, VALUE_TYPE: 'WORK' }] : [],
        EMAIL: [{ VALUE: w.email, VALUE_TYPE: 'WORK' }],
        COMMENTS: 'Organizator z aplikacji cennik.impresariatkoncertowy.pl',
      } });
      companyId = Number(created.result || 0);
    }
    if (companyId && !cf.COMPANY_ID) await req('crm.contact.update', { id: contactId, fields: { COMPANY_ID: companyId } });
  }
} catch (e) { /* wzbogacenie nie moze zablokowac deala */ }
return [{ json: { contactId, companyId } }];
